import{_ as e,o,c as l,ag as i}from"./chunks/framework.CTpQozEL.js";const w=JSON.parse('{"title":"플랫폼","description":"플랫폼 지원 개요 (게이트웨이 + 동반 앱)","frontmatter":{"title":"플랫폼","description":"플랫폼 지원 개요 (게이트웨이 + 동반 앱)"},"headers":[],"relativePath":"platforms/index.md","filePath":"platforms/index.md","lastUpdated":null}'),t={name:"platforms/index.md"};function n(c,a,r,d,s,p){return o(),l("div",null,[...a[0]||(a[0]=[i('<h1 id="플랫폼" tabindex="-1">플랫폼 <a class="header-anchor" href="#플랫폼" aria-label="Permalink to &quot;플랫폼&quot;">​</a></h1><p>OpenClaw 코어는 TypeScript로 작성되어 있습니다. <strong>Node가 권장 런타임입니다</strong>. 게이트웨이에는 Bun을 권장하지 않습니다 (WhatsApp/Telegram 버그).</p><p>macOS(메뉴 바 앱) 및 모바일 노드(iOS/Android)용 동반 앱이 존재합니다. Windows 및 Linux 동반 앱은 계획 중이지만, 게이트웨이는 현재 완전히 지원됩니다. Windows용 네이티브 동반 앱도 계획 중이며, 게이트웨이는 WSL2를 통해 권장됩니다.</p><h2 id="os-선택" tabindex="-1">OS 선택 <a class="header-anchor" href="#os-선택" aria-label="Permalink to &quot;OS 선택&quot;">​</a></h2><ul><li>macOS: <a href="/openclaw-docs-ko/platforms/macos">macOS</a></li><li>iOS: <a href="/openclaw-docs-ko/platforms/ios">iOS</a></li><li>Android: <a href="/openclaw-docs-ko/platforms/android">Android</a></li><li>Windows: <a href="/openclaw-docs-ko/platforms/windows">Windows</a></li><li>Linux: <a href="/openclaw-docs-ko/platforms/linux">Linux</a></li></ul><h2 id="vps-및-호스팅" tabindex="-1">VPS 및 호스팅 <a class="header-anchor" href="#vps-및-호스팅" aria-label="Permalink to &quot;VPS 및 호스팅&quot;">​</a></h2><ul><li>VPS 허브: <a href="/openclaw-docs-ko/vps">VPS 호스팅</a></li><li>Fly.io: <a href="/openclaw-docs-ko/install/fly">Fly.io</a></li><li>Hetzner (Docker): <a href="/openclaw-docs-ko/install/hetzner">Hetzner</a></li><li>GCP (Compute Engine): <a href="/openclaw-docs-ko/install/gcp">GCP</a></li><li>Azure (Linux VM): <a href="/openclaw-docs-ko/install/azure">Azure</a></li><li>exe.dev (VM + HTTPS 프록시): <a href="/openclaw-docs-ko/install/exe-dev">exe.dev</a></li></ul><h2 id="공통-링크" tabindex="-1">공통 링크 <a class="header-anchor" href="#공통-링크" aria-label="Permalink to &quot;공통 링크&quot;">​</a></h2><ul><li>설치 가이드: <a href="/openclaw-docs-ko/start/getting-started">시작하기</a></li><li>게이트웨이 런북: <a href="/openclaw-docs-ko/gateway/">게이트웨이</a></li><li>게이트웨이 구성: <a href="/openclaw-docs-ko/gateway/configuration">구성</a></li><li>서비스 상태: <code>openclaw gateway status</code></li></ul><h2 id="게이트웨이-서비스-설치-cli" tabindex="-1">게이트웨이 서비스 설치 (CLI) <a class="header-anchor" href="#게이트웨이-서비스-설치-cli" aria-label="Permalink to &quot;게이트웨이 서비스 설치 (CLI)&quot;">​</a></h2><p>다음 중 하나를 사용하십시오 (모두 지원됨):</p><ul><li>마법사 (권장): <code>openclaw onboard --install-daemon</code></li><li>직접: <code>openclaw gateway install</code></li><li>구성 흐름: <code>openclaw configure</code> → <strong>Gateway service</strong> 선택</li><li>복구/마이그레이션: <code>openclaw doctor</code> (서비스 설치 또는 수정 제안)</li></ul><p>서비스 대상은 OS에 따라 다릅니다:</p><ul><li>macOS: LaunchAgent (<code>ai.openclaw.gateway</code> 또는 <code>ai.openclaw.&lt;profile&gt;</code>; 레거시 <code>com.openclaw.*</code>)</li><li>Linux/WSL2: systemd 사용자 서비스 (<code>openclaw-gateway[-&lt;profile&gt;].service</code>)</li><li>네이티브 Windows: 예약된 작업 (<code>OpenClaw Gateway</code> 또는 <code>OpenClaw Gateway (&lt;profile&gt;)</code>), 작업 생성이 거부될 경우 사용자별 시작 폴더 로그인 항목 대체</li></ul>',14)])])}const f=e(t,[["render",n]]);export{w as __pageData,f as default};
